// Parse MCC historic recalculation request
const payload = $input.first().json.body || $input.first().json;
const d = payload.data || {};

return [{
  json: {
    event: 'mcc.historic.recalc',
    userId: d.userId,
    xrplAddress: d.xrplAddress,
    trigger: d.trigger || 'manual',
    currentMccCount: d.currentMccCount || 0,
    currentScore: d.currentScore || 0,
    timestamp: payload.timestamp
  }
}];

// Calculate craft standing based on MCC historic record
// Standing model (placeholder — refine with real data):
//   Base: 1 point per MCC credential
//   Bonus: +0.5 per unique skill domain
//   Bonus: +2 for dispute-free record
//   Penalty: -5 per lost dispute
const data = $input.first().json;

const mccCount = data.currentMccCount || 0;
const baseScore = mccCount * 1;
const uniqueDomainBonus = 0; // TODO: calculate from MCC metadata
const disputeFreeBonus = 2; // TODO: check dispute history
const disputePenalty = 0; // TODO: count lost disputes

const newScore = Math.max(0, baseScore + uniqueDomainBonus + disputeFreeBonus - disputePenalty);

// Tier calculation
let tier = 'Bronze';
if (newScore >= 50) tier = 'Diamond';
else if (newScore >= 25) tier = 'Platinum';
else if (newScore >= 10) tier = 'Gold';
else if (newScore >= 5) tier = 'Silver';

console.log(`[StudioLedger] MCC HISTORIC RECALC: User ${data.userId}`);
console.log(`[StudioLedger] MCCs: ${mccCount}, Standing: ${data.currentScore} -> ${newScore}`);
console.log(`[StudioLedger] Tier: ${tier}`);

return [{
  json: {
    userId: data.userId,
    xrplAddress: data.xrplAddress,
    previousScore: data.currentScore,
    newScore,
    tier,
    mccCount,
    components: {
      baseScore,
      uniqueDomainBonus,
      disputeFreeBonus,
      disputePenalty
    },
    qualifiesForArbitration: newScore >= 10 && mccCount >= 5,
    calculatedAt: new Date().toISOString()
  }
}];

// Standing changed — update DB and notify user
const data = $input.first().json;

console.log(`[StudioLedger] STANDING UPDATED: ${data.userId}`);
console.log(`[StudioLedger] ${data.previousScore} -> ${data.newScore} (${data.tier})`);
if (data.qualifiesForArbitration) {
  console.log(`[StudioLedger] User now qualifies for arbitration panels!`);
}

// TODO: Update Supabase users.craft_standing
// TODO: Send notification if tier changed

return [{
  json: {
    ...data,
    updated: true,
    message: `MCC historic updated: ${data.previousScore} -> ${data.newScore} (${data.tier})`
  }
}];

// No change — skip
const data = $input.first().json;
console.log(`[StudioLedger] Standing unchanged for ${data.userId}: ${data.newScore} (${data.tier})`);
return [{ json: { ...data, updated: false, message: 'No standing change' } }];
